305.     /// <param name="comparedTo">The reference date (typically DateTime.UtcNow).</param>
306.     /// <returns>A human-readable string representing the time difference.</returns>
307.     public string Humanize(DateTime input, DateTime comparedTo)
308.     {
309.         var difference = comparedTo - input;
310.         if (Math.Abs(difference.TotalSeconds) < 2)
311.         {
312.             return "just now";
313.         }
314. 
315.         var isFuture = difference.TotalSeconds < 0;
316.         var absDiff = difference.Duration();
317. 
318.         var result = absDiff.TotalDays switch
319.         {
320.             >= 365 => $"{(int)(absDiff.TotalDays / 365)} years",
321.             >= 31 => $"{(int)(absDiff.TotalDays / 30)} months",
322.             >= 1 => $"{(int)absDiff.TotalDays} days",
323.             _ => absDiff.TotalHours switch
324.             {
325.                 >= 1 => $"{(int)absDiff.TotalHours} hours",
326.                 _ => absDiff.TotalMinutes switch
327.                 {
